output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?attendance WHERE {
  {
    ?game wdt:P159 wd:Q334634 ; wdt:P1994 wd:Q650840 ; wdt:P653 ?attendance ; wdt:P527 ?series .
  } UNION {
    ?game wdt:P159 wd:Q650840 ; wdt:P1994 wd:Q334634 ; wdt:P653 ?attendance ; wdt:P527 ?series .
  }
  ?series wdt:P31 wd:Q1363275 .
}
ORDER BY DESC(?attendance)
LIMIT 1

